INSERT INTO appreciation_letters (letter_id, kindergarten_id, sender_user_id, target_type, target_id, title, content, is_public, status, created_at, updated_at) VALUES
(16, 1, 231, 'TEACHER', 12, '늘 따뜻하게 맞아 주셔서 감사합니다', $$첫 등원 날 아이가 많이 울었는데, 선생님께서 차분히 달래 주시고 하루 종일 연락도 잘 주셔서 안심했습니다. 바쁘신 와중에도 한 아이 한 아이를 세심히 보살펴 주셔서 진심으로 감사드립니다.$$, true, 'ACTIVE', '2026-03-22 09:15:00+09', '2026-03-22 09:15:00+09'),
(15, 1, 232, 'KINDERGARTEN', 1, '원 전체가 함께 만들어 주는 안심 환경', $$행사 준비부터 안전 교육, 급식 안내까지 항상 투명하게 알려 주셔서 부모 입장에서 큰 힘이 됩니다. 원장님과 모든 선생님, 행정 선생님들께도 감사의 말씀 전합니다.$$, true, 'ACTIVE', '2026-03-20 14:40:00+09', '2026-03-20 14:40:00+09'),
(14, 1, 233, 'TEACHER', 8, '말하기 수업 덕분에 아이가 자신감을 얻었어요', $$집에서는 조용했던 아이가 요즘은 학교에서 있었던 일을 스스로 이야기해 줍니다. 칭찬과 격려를 아끼지 않으신 덕분이라 생각합니다. 앞으로도 잘 부탁드립니다.$$, false, 'ACTIVE', '2026-03-18 11:05:00+09', '2026-03-19 08:30:00+09'),
(13, 2, 434, 'TEACHER', 31, '체육 시간과 놀이 활동에 대한 감사', $$운동 신경이 서툴던 아이가 집에서도 “오늘은 이렇게 뛰었어요”라며 즐겁게 말합니다. 무리하지 않게 지도해 주시는 모습이 인상 깊었습니다.$$, true, 'PENDING', '2026-03-15 16:20:00+09', '2026-03-15 16:20:00+09'),
(12, 1, 235, 'KINDERGARTEN', 1, '소통이 빠른 알림장과 앱 안내에 감사드립니다', $$돌발 일정이나 준비물 변경이 있을 때마다 빠르게 공지해 주셔서 직장을 다니는 부모로서 정말 든든합니다. 번거로우실 텐데 매번 챙겨 주셔서 감사합니다.$$, true, 'ACTIVE', '2026-03-12 07:50:00+09', '2026-03-12 07:50:00+09'),
(11, 1, 236, 'TEACHER', 12, '별이 친구들과 잘 지내게 도와주셔서', $$또래 관계에서 어려움이 있을 때 중재해 주시고, 서로의 감정을 이야기할 수 있게 이끌어 주신다고 들었습니다. 아이의 사회성이 한층 자란 것 같아 감사합니다.$$, false, 'ACTIVE', '2026-03-10 13:12:00+09', '2026-03-10 13:12:00+09'),
(10, 2, 437, 'TEACHER', 32, '영어 놀이 활동이 너무 좋았습니다', $$부담 없이 노래와 게임으로 접하게 해 주셔서 아이가 영어에 거부감 없이 즐깁니다. 연령에 맞는 수준 조절도 잘 되어 있는 것 같습니다.$$, true, 'ACTIVE', '2026-03-08 10:00:00+09', '2026-03-08 10:00:00+09'),
(9, 1, 238, 'KINDERGARTEN', 1, '봄 소풍 준비와 안전 배려에 감사합니다', $$응급 상황 대비 안내와 분만 물품 챙김표까지 꼼꼼히 보내 주셔서 준비가 수월했습니다. 아이들 안전을 최우선으로 생각해 주시는 모습에 감사드립니다.$$, true, 'DISABLED', '2026-03-05 09:00:00+09', '2026-03-06 15:00:00+09'),
(8, 1, 239, 'TEACHER', 9, '미술 작품 하나하나에 담긴 격려', $$완성도와 상관없이 과정을 존중해 주시는 말씀 덕분에 아이가 그림 그리는 것을 좋아하게 되었습니다. 작은 변화도 알아봐 주셔서 감사합니다.$$, true, 'ACTIVE', '2026-03-01 15:45:00+09', '2026-03-01 15:45:00+09'),
(7, 2, 430, 'TEACHER', 30, '식습관 교정을 부드럽게 도와주셔서', $$편식이 심했는데, 선생님께서 친구들과 함께 먹는 분위기를 만들어 주신 덕분에 점차 나아지고 있습니다. 식단 정보도 감사드립니다.$$, false, 'PENDING', '2026-02-26 12:30:00+09', '2026-02-26 12:30:00+09'),
(6, 1, 231, 'KINDERGARTEN', 1, '겨울 방학 연장 돌봄 운영에 감사드립니다', $$맞벌이 가정에 방학 돌봄은 큰 도움이 됩니다. 프로그램도 알차게 구성해 주셔서 아이가 지루해하지 않고 다녀왔다고 합니다.$$, true, 'ACTIVE', '2026-02-20 08:20:00+09', '2026-02-20 08:20:00+09'),
(5, 1, 232, 'TEACHER', 11, '음악 줄넘기 발표회, 잊지 못할 추억이 되었습니다', $$연습 과정에서 낙담할 때마다 격려해 주시고, 무대에서 웃을 수 있게 해 주셔서 감사합니다. 가족 모두 감동했습니다.$$, true, 'ACTIVE', '2026-02-14 18:00:00+09', '2026-02-14 18:00:00+09'),
(4, 2, 433, 'TEACHER', 33, '수조작·블록 놀이로 집중력이 늘었어요', $$한 가지 활동에 오래 머무는 연습이 집에서도 이어진다고 느낍니다. 재료 준비와 정리 교육까지 세심하신 점 감사드립니다.$$, true, 'ACTIVE', '2026-02-08 09:40:00+09', '2026-02-08 09:40:00+09'),
(3, 1, 234, 'KINDERGARTEN', 1, '건강검진·알레르기 대응 안내 감사합니다', $$우리 아이 알레르기 정보를 기억해 주시고 급식에 반영해 주셔서 안심하고 맡길 수 있었습니다. 건강 관련 공지도 항상 명확해서 좋습니다.$$, false, 'ACTIVE', '2026-02-01 14:10:00+09', '2026-02-01 14:10:00+09'),
(2, 1, 235, 'TEACHER', 10, '독서 동아리 덕분에 책과 친해졌습니다', $$매주 책을 고르고 이야기 나누는 시간이 아이에게는 가장 기다려진 시간이 되었습니다. 좋은 도서 추천도 감사드립니다.$$, true, 'PENDING', '2026-01-22 11:25:00+09', '2026-01-22 11:25:00+09'),
(1, 3, 736, 'TEACHER', 52, '한 해 동안 정말 고생 많으셨습니다', $$어린이집 생활을 시작할 때부터 지금까지 성장의 발자국마다 함께해 주신 담임 선생님께 깊이 감사드립니다. 내년에도 잘 부탁드립니다.$$, true, 'ACTIVE', '2026-01-10 17:00:00+09', '2026-01-11 10:00:00+09');
